	@Test
	public void testFilteredBindingSetAssignmentJoinUsesFusedAlgorithm() {
		BindingSetAssignment left = new BindingSetAssignment();
		left.setBindingSets(List.of(binding("a", "1"), binding("a", "2")));

		BindingSetAssignment right = new BindingSetAssignment();
		right.setBindingSets(List.of(binding("b", "1"), binding("b", "2")));

		Join join = new Join(left, right);
		Filter filter = new Filter(join, new Compare(Var.of("a"), Var.of("b"), Compare.CompareOp.NE));
		CloseableIteration<BindingSet> result = evaluator
				.precompile(filter)
				.evaluate(EmptyBindingSet.getInstance());

		List<BindingSet> rows = Iterations.asList(result);

		assertEquals("FilteredBindingSetAssignmentJoinIteration", join.getAlgorithmName());
		assertEquals(2, rows.size());
		for (BindingSet row : rows) {
			assertNotEqual(row.getValue("a"), row.getValue("b"));
		}
	}

	private void testBindingSetAssignmentJoin(int expectedSize, int n, BindingSet bindings)
			throws QueryEvaluationException {
		BindingSetAssignment left = new BindingSetAssignment();
		{
			List<BindingSet> leftb = new ArrayList<>();
			for (int i = 0; i < n; i++) {
				QueryBindingSet b = new QueryBindingSet();
				b.addBinding("a", vf.createLiteral(i));
				leftb.add(b);
			}
			left.setBindingSets(leftb);
		}

		BindingSetAssignment right = new BindingSetAssignment();
		{
			List<BindingSet> rightb = new ArrayList<>();
			for (int i = n; i >= 0; i--) {
				QueryBindingSet b = new QueryBindingSet();
				b.addBinding("a", vf.createLiteral(i));
				rightb.add(b);
			}
			right.setBindingSets(rightb);
		}

		var lrIter = JoinIterator.getInstance(evaluator.precompile(left), evaluator.precompile(right), bindings);
		Set<BindingSet> lr = Iterations.asSet(lrIter);
		assertEquals(expectedSize, lr.size());

		var rlIter = JoinIterator.getInstance(evaluator.precompile(right), evaluator.precompile(left), bindings);
		Set<BindingSet> rl = Iterations.asSet(rlIter);
		assertEquals(expectedSize, rl.size());

		assertEquals(lr, rl);

		// check bindings
		for (BindingSet b : lr) {
			for (String name : bindings.getBindingNames()) {
				assertEquals(bindings.getValue(name), b.getValue(name));
			}
		}
	}

	private BindingSet binding(String name, String value) {
		QueryBindingSet bindingSet = new QueryBindingSet();
		bindingSet.addBinding(name, vf.createLiteral(value));
		return bindingSet;
	}

	private static void assertNotEqual(Value left, Value right) {
		if (left.equals(right)) {
			throw new AssertionError("Expected different values, got " + left);
		}
	}

	private final class CountingTripleSource implements TripleSource {

		private final Statement statement = vf.createStatement(
				vf.createIRI("urn:subj"),
				vf.createIRI("urn:pred"),
				vf.createLiteral("obj"));
		private final Statement secondStatement = vf.createStatement(
				statement.getSubject(),
				vf.createIRI("urn:pred2"),
				vf.createLiteral("obj2"));
		private int countLookupCount;
		private int statementLookupCount;

		@Override
		public CloseableIteration<? extends Statement> getStatements(Resource subj, IRI pred,
				Value obj, Resource... contexts) {
			statementLookupCount++;
			for (Statement candidate : List.of(statement, secondStatement)) {
				if (!candidate.getSubject().equals(subj)
						|| !candidate.getPredicate().equals(pred)
						|| !candidate.getObject().equals(obj)) {
					continue;
				}
				return new org.eclipse.rdf4j.common.iteration.CloseableIteratorIteration<>(
						List.of(candidate).iterator());
			}
			return new org.eclipse.rdf4j.common.iteration.CloseableIteratorIteration<>(
					List.<Statement>of().iterator());
		}

		@Override
		public long getStatementCount(Resource subj, IRI pred, Value obj, Resource... contexts) {
			countLookupCount++;
			for (Statement candidate : List.of(statement, secondStatement)) {
				if (candidate.getSubject().equals(subj)
						&& candidate.getPredicate().equals(pred)
						&& candidate.getObject().equals(obj)) {
					return 1;
				}
			}
			return 0;
		}

		@Override
		public ValueFactory getValueFactory() {
			return vf;
		}
	}
